try {
  // Extract email data from Gmail API full response
  const item = $input.first().json;
  const payload = item.payload;
  const headers = payload.headers || [];

  // Extract From header
  const fromHeader = headers.find(h => h.name === 'From')?.value || '';

  // Extract Subject header  
  const subjectHeader = headers.find(h => h.name === 'Subject')?.value || '';

  // Extract To header
  const toHeader = headers.find(h => h.name === 'To')?.value || '';

  // Extract Cc header
  const ccHeader = headers.find(h => h.name === 'Cc')?.value || '';

  let bodyHtml = '';
  let bodyText = '';
  const attachmentIds = [];

  // Recursive function to extract body and attachments
  function parseParts(part) {
    if (!part) return;

    const mimeType = part.mimeType || '';

    // Extract body content
    if (mimeType === 'text/html' && part.body?.data) {
      if (!bodyHtml) {
        try {
          bodyHtml = Buffer.from(part.body.data, 'base64').toString('utf-8');
        } catch (e) {
          // Fallback if not base64
          bodyHtml = part.body.data;
        }
      }
    } else if (mimeType === 'text/plain' && part.body?.data) {
      if (!bodyText) {
        try {
          bodyText = Buffer.from(part.body.data, 'base64').toString('utf-8');
        } catch (e) {
          // Fallback if not base64
          bodyText = part.body.data;
        }
      }
    }

    // Extract attachment metadata
    if (part.filename && part.body?.attachmentId) {
      attachmentIds.push({
        id: part.body.attachmentId,
        filename: part.filename,
        mimeType: part.mimeType,
        size: part.body.size
      });
    }

    // Recursively process parts
    if (part.parts && Array.isArray(part.parts)) {
      part.parts.forEach(parseParts);
    }
  }

  // Start parsing from the top-level payload
  parseParts(payload);

  return {
    From: fromHeader,
    To: toHeader,
    Cc: ccHeader,
    Subject: subjectHeader,
    bodyHtml: bodyHtml,
    bodyText: bodyText,
    attachmentIds: attachmentIds,
    messageId: item.id
  };

} catch (error) {
  throw new Error(`Extract Email Data failed: ${error.message}`);
}

const from = $json.From || '';
let targetRecipientTO = '';
let targetRecipientCC = '';

if (from.includes('hrm@pebsteel.com.vn')) {
  targetRecipientTO = 'loi@pebsteel.com.vn,ntb@pebsteel.com.vn,thv@pebsteel.com.vn,tnq@pebsteel.com.vn,ntn@pebsteel.com.vn';
  targetRecipientCC = '';
} else if (from.includes('Vung Tau') || from.includes('Vungtau')) {
  targetRecipientTO = 'tnq@pebsteel.com.vn,ntn@pebsteel.com.vn';
  targetRecipientCC = 'loi@pebsteel.com.vn';
} else if (from.includes('HCMC')) {
  targetRecipientTO = 'ntb@pebsteel.com.vn,loi@pebsteel.com.vn,thv@pebsteel.com.vn';
  targetRecipientCC = '';
} else {
  targetRecipientTO = 'loi@pebsteel.com.vn';
  targetRecipientCC = '';
}

const targetRecipient = targetRecipientTO + (targetRecipientCC ? ',' + targetRecipientCC : '');

return { 
  ...$json, 
  targetRecipient: targetRecipient,
  targetRecipientTO: targetRecipientTO,
  targetRecipientCC: targetRecipientCC
};

const attachmentIds = $json.attachmentIds;
const baseData = { ...$json };
delete baseData.attachmentIds;

return attachmentIds.map(att => ({
  ...baseData,
  attachmentId: att.id,
  attachmentFilename: att.filename,
  attachmentMimeType: att.mimeType
}));

// Combine all downloaded attachments into a single item
// Gmail Send Email expects all attachments under binary keys
const items = $input.all();

if (items.length === 0) {
  // Return item with empty binaryFieldNames so Check Binary Exists routes to "no attachments" path
  return {
    json: {
      From: '',
      Subject: '',
      bodyHtml: '',
      bodyText: '',
      targetRecipient: '',
      targetRecipientTO: '',
      targetRecipientCC: '',
      messageId: '',
      attachmentCount: 0,
      binaryFieldNames: ''  // Empty string will fail "notEmpty" check
    },
    binary: {}
  };
}

// Get email data from first item (all items have same email data)
const emailData = items[0].json;

// Create result with email data
const result = {
  json: {
    From: emailData.From || '',
    Subject: emailData.Subject || '',
    bodyHtml: emailData.bodyHtml || '',
    bodyText: emailData.bodyText || '',
    targetRecipient: emailData.targetRecipient || '',
    targetRecipientTO: emailData.targetRecipientTO || '',
    targetRecipientCC: emailData.targetRecipientCC || '',
    messageId: emailData.messageId || '',
    attachmentCount: items.length,
    binaryFieldNames: ''  // Initialize with empty string
  },
  binary: {}
};

// Add each attachment as a separate binary property and track the keys
const binaryKeys = [];
items.forEach((item, index) => {
  if (item.binary && item.binary.data) {
    const binaryKey = index === 0 ? 'data' : `data${index}`;
    result.binary[binaryKey] = item.binary.data;
    binaryKeys.push(binaryKey);
  }
});

// Set binaryFieldNames - will be empty string if no binary data found
result.json.binaryFieldNames = binaryKeys.length > 0 ? binaryKeys.join(',') : '';

return result;

// Decode Gmail attachment from base64url and create binary data
const items = $input.all();
const splitAttachmentsItems = $('Split Attachments').all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const sourceItem = splitAttachmentsItems[i];

  // Get filename and mimeType from the original Split Attachments node
  const filename = sourceItem?.json?.attachmentFilename || 'attachment';
  const mimeType = sourceItem?.json?.attachmentMimeType || 'application/octet-stream';

  // Get attachment data - try multiple locations
  let attachmentDataStr;
  if (item.json.attachmentData?.data) {
    attachmentDataStr = item.json.attachmentData.data;
  } else if (item.json.data) {
    attachmentDataStr = item.json.data;
  } else {
    throw new Error('Could not find attachment data. Available keys: ' + Object.keys(item.json).join(', ') + '. Full JSON: ' + JSON.stringify(item.json));
  }

  // Decode base64url to buffer
  const base64Data = attachmentDataStr.replace(/-/g, '+').replace(/_/g, '/');
  const buffer = Buffer.from(base64Data, 'base64');

  // Extract file extension
  const fileExtension = filename.includes('.') ? filename.split('.').pop() : '';

  results.push({
    json: {
      From: sourceItem.json.From || '',
      Subject: sourceItem.json.Subject || '',
      bodyHtml: sourceItem.json.bodyHtml || '',
      bodyText: sourceItem.json.bodyText || '',
      targetRecipient: sourceItem.json.targetRecipient || '',
      targetRecipientTO: sourceItem.json.targetRecipientTO || '',
      targetRecipientCC: sourceItem.json.targetRecipientCC || '',
      messageId: sourceItem.json.messageId || '',
      attachmentFilename: filename
    },
    binary: {
      data: {
        data: buffer.toString('base64'),
        mimeType: mimeType,
        fileName: filename,
        fileExtension: fileExtension
      }
    }
  });
}

return results;

// Get the original messageId from the Extract Email Data node
const extractedData = $('Extract Email Data').first().json;
const messageId = extractedData.messageId;

// Get targetRecipient from Compute Recipient node
const computedData = $('Compute Recipient').first().json;
const targetRecipientTO = computedData.targetRecipientTO || '';
const targetRecipientCC = computedData.targetRecipientCC || '';

// Extract sender email from original data
const senderEmail = extractedData.From || '';
const emailMatch = senderEmail.match(/([a-zA-Z0-9._-]+)@/);
const emailPrefix = emailMatch ? emailMatch[1] : '';
const senderName = emailPrefix.substring(0, 3).toUpperCase() || 'SENDER';

// Extract just the email address from From header (remove name if present)
// From header format: "Name <email@domain.com>" or "email@domain.com"
const emailAddressMatch = senderEmail.match(/<(.+?)>/) || senderEmail.match(/([^\\s]+@[^\\s]+)/);
const senderEmailAddress = emailAddressMatch ? emailAddressMatch[1] : senderEmail;

// Extract receiver names from TO recipients
const toEmails = targetRecipientTO.split(',').map(e => e.trim()).filter(e => e);
const toNames = toEmails.map(email => {
  const match = email.match(/([a-zA-Z0-9._-]+)@/);
  return match ? match[1].toUpperCase() : email;
}).filter(name => name !== null && name !== '');

// Extract receiver names from CC recipients
const ccEmails = targetRecipientCC.split(',').map(e => e.trim()).filter(e => e);
const ccNames = ccEmails.map(email => {
  const match = email.match(/([a-zA-Z0-9._-]+)@/);
  return match ? match[1].toUpperCase() : email;
}).filter(name => name !== null && name !== '');

// Format receiver message with TO and CC distinction
let forwardedToMessage = '';
if (toNames.length > 0 && ccNames.length > 0) {
  forwardedToMessage = '<strong>' + toNames.join(', ') + '</strong> (with CC to <strong>' + ccNames.join(', ') + '</strong>)';
} else if (toNames.length > 0) {
  forwardedToMessage = '<strong>' + toNames.join(', ') + '</strong>';
}

// Create reply message with HTML formatting
const subject = extractedData.Subject || 'your request';
const replyMessage = '<div style="font-family: Arial, sans-serif;">Dear ' + senderName + ',<br><br>Thank you for contacting IT Helpdesk.<br><br>We have received your email about "<strong>' + subject + '</strong>" and forwarded it to: ' + forwardedToMessage + '.<br><br>They will assist you shortly.<br><br>Best regards,<br>Pebsteel IT Helpdesk Team</div>';

// Create custom subject
const replySubject = 'Re: ' + subject + ' - Your information was received';

return {
  messageId: messageId,
  replyMessage: replyMessage,
  replySubject: replySubject,
  senderEmailAddress: senderEmailAddress,
  receiverNamesTO: toNames.join(', '),
  receiverNamesCC: ccNames.length > 0 ? ccNames.join(', ') : 'N/A',
  From: extractedData.From,
  Subject: extractedData.Subject
};

// Prepare data for Google Sheets logging
const from = $json.From || '';
const subject = $json.Subject || '';
const bodyHtml = $json.bodyHtml || '';
const bodyText = $json.bodyText || '';
const targetRecipientTO = $json.targetRecipientTO || '';
const targetRecipientCC = $json.targetRecipientCC || '';
const messageId = $json.messageId || '';
const attachmentIds = $json.attachmentIds || [];

// Extract email address and name from From header
let fromEmail = '';
let fromName = '';

const emailMatch = from.match(/<(.+?)>/);
if (emailMatch) {
  fromEmail = emailMatch[1];
  fromName = from.replace(/<.+?>/, '').trim();
} else {
  fromEmail = from.trim();
  fromName = from.trim();
}

// Create body preview with preserved line breaks
let bodyPreview = bodyText || bodyHtml || '';

if (bodyHtml) {
  bodyPreview = bodyPreview.replace(/<br\s*\/?>/gi, '\n');
  bodyPreview = bodyPreview.replace(/<\/p>/gi, '\n\n');
  bodyPreview = bodyPreview.replace(/<p[^>]*>/gi, '');
  bodyPreview = bodyPreview.replace(/<\/div>/gi, '\n');
  bodyPreview = bodyPreview.replace(/<div[^>]*>/gi, '');
}

bodyPreview = bodyPreview.replace(/<[^>]*>/g, '');
bodyPreview = bodyPreview.replace(/\n{3,}/g, '\n\n');
bodyPreview = bodyPreview.replace(/[ \t]+/g, ' ');
bodyPreview = bodyPreview.trim();
bodyPreview = bodyPreview.substring(0, 500);
if (bodyPreview.length === 500) {
  bodyPreview += '...';
}

// Format TO recipients (extract names)
const toEmails = targetRecipientTO.split(',').map(e => e.trim()).filter(e => e);
const toNames = toEmails.map(email => {
  const match = email.match(/([a-zA-Z0-9._-]+)@/);
  return match ? match[1].toUpperCase() : email;
}).join(', ');

// Format CC recipients (extract names) with N/A handling
const ccEmails = targetRecipientCC.split(',').map(e => e.trim()).filter(e => e);
const ccNames = ccEmails.length > 0 
  ? ccEmails.map(email => {
      const match = email.match(/([a-zA-Z0-9._-]+)@/);
      return match ? match[1].toUpperCase() : email;
    }).join(', ')
  : 'N/A';

// Attachment info
const hasAttachments = attachmentIds.length > 0 ? 'Yes' : 'No';
const attachmentCount = attachmentIds.length;

// Current timestamp
const timestamp = $now.toFormat('yyyy-MM-dd HH:mm:ss');

return {
  Timestamp: timestamp,
  FromEmail: fromEmail,
  FromName: fromName,
  Subject: subject,
  BodyPreview: bodyPreview,
  RecipientsTO: toNames,
  RecipientsCC: ccNames,
  HasAttachments: hasAttachments,
  AttachmentCount: attachmentCount.toString(),
  MessageID: messageId
};
